import api from './api';

export const productService = {
  getAllProducts: async () => (await api.get('/api/products')).data,
  getProductById: async (id) => (await api.get(`/api/products/${id}`)).data,
  createProduct: async (product) => (await api.post('/api/products', product)).data,
  updateProduct: async (id, product) => (await api.put(`/api/products/${id}`, product)).data,
  deleteProduct: async (id) => (await api.delete(`/api/products/${id}`)).data,
  searchByName: async (name) => (await api.get(`/api/products/search/${name}`)).data,
};
